INSERT INTO jiaohuanjilu (addtime, yonghuzhanghao, yonghuxingming, shoujihao, biaoti, jinengfenlei, gongjitupian, jiaohuanjineng, jiaohuanshijian, gongjineirong, gongjirenzhanghao, gongjirenxingming, lianxifangshi, crossuserid, crossrefid, fabuzhetigong, shenqingrentigong) VALUES ('2026-04-29 10:00:00', 'zhaoyang', '赵阳', '13812046578', '考研政治辅导', '学习', 'upload/jiaohuanjilu_考研政治辅导1.jpg', '学习', '2026-04-29', '赵阳详细讲解了马原和毛概的核心考点，梳理了历年真题出题规律，提供了针对性的复习计划和答题模板', 'zhoukai', '周凯', '13812348756', 16, 1, '考研政治辅导', '毛笔书法国画入门'),
