INSERT INTO pingjiafankui (addtime, yonghuzhanghao, yonghuxingming, shoujihao, biaoti, jinengfenlei, huifutupian, jiaohuanjineng, pingjiashijian, jiaohuanbeizhu, jiaohuanrenzhanghao, jiaohuanrenxingming, lianxifangshi, huifuneirong, pingjiajieguo, huifushipin, huifufujian, sfsh, shhf) VALUES ('2026-04-29 11:00:00', 'zhoukai', '周凯', '13812348756', '考研政治辅导', '学习', 'upload/pingjiafankui_考研政治辅导1.jpg', '学习', '2026-04-29', '线上视频辅导加课后答疑', 'zhaoyang', '赵阳', '13812046578', '赵阳同学的政治辅导非常系统！马原部分的哲学原理梳理得很清晰，每个知识点都配有历年真题例证。特别感谢他整理的答题模板，用起来特别顺手。强烈推荐给备考的同学！', '好评', '', '', '是', ''),
('2026-04-29 11:30:00', 'zhaoyang', '赵阳', '13812046578', '毛笔书法国画入门', '艺术', 'upload/pingjiafankui_毛笔书法国画1.jpg', '艺术', '2026-04-29', '线下书法教室面对面教学', 'zhoukai', '周凯', '13812348756', '周凯同学的书法功底真的很深厚！从执笔姿势到基本笔法都讲解得很细致，还现场示范了楷书永字八法。一节课下来感觉自己写字好看了不少。', '好评', '', '', '是', ''),
('2026-04-29 09:00:00', 'wufang', '吴芳', '15065437821', 'Figma界面设计', '设计', 'upload/pingjiafankui_Figma界面设计1.jpg', '设计', '2026-04-29', '线上Figma协作教学', 'liumin', '刘敏', '15178903456', '刘敏的Figma教学非常专业！从基础操作到高级功能一步步带着做，特别是自动布局和组件变体的讲解让我豁然开朗。帮我的毕设APP做了完整的UI设计方案，导师看了都说很规范。', '好评', '', '', '是', ''),
('2026-04-29 09:30:00', 'liumin', '刘敏', '15178903456', 'PS海报设计', '设计', 'upload/pingjiafankui_PS海报设计交换1.jpg', '设计', '2026-04-29', '线上远程协作', 'wufang', '吴芳', '15065437821', '吴芳的PS海报设计水平很高！配色感觉非常好，排版也很有创意。讲解PS蒙版和图层混合模式时也很有耐心，让我对PS有了更深的理解。', '好评', '', '', '是', '');

